class AllOne:

    def __init__(self):
        self.count = {}
        self.min_key = ""
        self.max_key = ""

    def inc(self, key: str) -> None:
        if key not in self.count:
            self.count[key] = 1
        else:
            self.count[key] += 1
        if self.max_key and self.count[self.max_key] < self.count[key]:
            self.max_key = key
        if not self.min_key or self.count[self.min_key] > self.count[key]:
            self.min_key = key

    def dec(self, key: str) -> None:
        self.count[key] -= 1
        if self.count[key] == 0:
            del self.count[key]
            if key == self.max_key:
                for k in self.count:
                    if self.count[k] > self.count.get(self.max_key, 0):
                        self.max_key = k
            if key == self.min_key:
                for k in self.count:
                    if self.count[k] < self.count.get(self.min_key, float('inf')):
                        self.min_key = k

    def getMaxKey(self) -> str:
        return self.max_key

    def getMinKey(self) -> str:
        return self.min_key
